import { pool } from "../server/storage";

interface EncEntry {
  slug: string; title: string; category: string;
  seoTitle: string; seoDescription: string; seoKeywords: string[];
  overview: string; mechanismPhysiology: string; clinicalRelevance: string;
  signsSymptoms: string; assessment: string; management: string; complications: string;
  clinicalPearls: string[]; examPitfalls: string[];
  faqJson: { question: string; answer: string }[];
}

function makeEntry(e: EncEntry) {
  return { profession: "mlt", status: "published", relatedLessonIds: [] as string[], relatedQuestionIds: [e.category], ...e };
}

